[FormControlEventHandler(formControlStr(ETGACFParameters, ETGACFParameters_Generaljournal), FormControlEventType::Lookup)]
public static void ETGACFParameters_Generaljournal_OnLookup(FormControl sender, FormControlEventArgs e)
{
    SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(LedgerJournalName), sender);
    Query query = new Query();
    QueryBuildDataSource qbds = query.addDataSource(tableNum(LedgerJournalName));
    QueryBuildRange qbr = qbds.addRange(fieldNum(LedgerJournalName, JournalType));
    qbr.value(queryValue(LedgerJournalType::Daily));
    sysTableLookup.addLookupField(fieldNum(LedgerJournalName, JournalName));
    sysTableLookup.addLookupField(fieldNum(LedgerJournalName, Name));
    sysTableLookup.parmQuery(query);
    sysTableLookup.parmUseLookupValue(false);
    sysTableLookup.performFormLookup();
}
